PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?broadcaster ?broadcasterLabel WHERE {
  ?event wdt:P31 wd:Q8291 ; wdt:P17 wd:Q16 ; wdt:P585 ?eventDate .
  FILTER(YEAR(?eventDate) = 2010)
  ?event wdt:P258 ?broadcaster .
  OPTIONAL {
    ?broadcaster rdfs:label ?broadcasterLabel
    FILTER(LANG(?broadcasterLabel) = 'en')
  }
}

